package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.artikel.dto.PersoonDTO;
import be.schaubroeck.lpb.rkm.rekenmotor.dto.ArtikelagendaDTO;
import be.schaubroeck.lpb.rkm.rekenmotor.dto.EvbDTO;
import be.schaubroeck.lpb.rkm.rekenmotor.dto.RekenagendaDTO;
import be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding.RekenVoorbereiding;
import be.schaubroeck.lpb.tools.ArtikelAgenda;
import be.schaubroeck.lpb.tools.ElektronischeVoorbereiding;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RekenAgenda;
import be.schaubroeck.lpb.tools.Werkgever;
import be.schaubroeck.lpb.tools.api.dto.CodeEnumDTO;
import be.schaubroeck.lpb.tools.api.dto.IdentifiableDTO;
import be.schaubroeck.lpb.tools.api.dto.IdentifiableVersionedDTO;
import be.schaubroeck.lpb.tools.enumtypes.CodeEnum;
import be.schaubroeck.lpb.tools.enumtypes.Rekengroep;
import be.schaubroeck.util.persistence.IdentifiableVersioned;
import lombok.NoArgsConstructor;
import org.hibernate.Hibernate;
import org.joda.time.LocalDate;

import java.util.ArrayList;
import java.util.Collection;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.function.Function;
import java.util.stream.Collectors;

@NoArgsConstructor
public class RekenmotorDtoConverter {

    private Map<Integer, Werkgever> werkgeverNrToWerkgever = new HashMap<>();
    private Map<Integer, Integer> werkgeverIdToWerkgeverNr = new HashMap<>();

    public RekenmotorDtoConverter(List<Werkgever> werkgevers) {
        werkgeverNrToWerkgever = werkgevers.stream().collect(Collectors.toMap(Werkgever::getWerkgeverNr, Function.identity()));
        werkgeverIdToWerkgeverNr = werkgevers.stream().collect(Collectors.toMap(Werkgever::getId, Werkgever::getWerkgeverNr));
    }

    //TODO kd dubbel met RekenmotorWebConvertor
    public CodeEnumDTO convert(CodeEnum enumType) {
        CodeEnumDTO codeEnumDTO = null;
        if (enumType != null) {
            codeEnumDTO = new CodeEnumDTO();
            codeEnumDTO.setId(enumType.getId());
            codeEnumDTO.setCode(enumType.getCode());
            codeEnumDTO.setKorteTekst(enumType.getKorteTekst());
            codeEnumDTO.setLangeTekst(enumType.getLangeTekst());
            codeEnumDTO.setToonInListbox(enumType.toonInListbox());
        }
        return codeEnumDTO;
    }

    public List<RekenagendaDTO> convertRekenagendas(List<RekenAgenda> rekenAgendas) {
        List<RekenagendaDTO> rekenagendaDTOs = new ArrayList<>();
        for (RekenAgenda rekenAgenda : rekenAgendas) {
            rekenagendaDTOs.add(convert(rekenAgenda));
        }
        return rekenagendaDTOs;
    }

    public RekenagendaDTO convert(RekenAgenda rekenAgendaPO) {
        RekenagendaDTO rekenagendaDTO = new RekenagendaDTO();
        setIdVersion(rekenagendaDTO, rekenAgendaPO);
        rekenagendaDTO.setBeginDatum(rekenAgendaPO.getBeginDatum());
        rekenagendaDTO.setEindDatum(rekenAgendaPO.getEindDatum());
        rekenagendaDTO.setRekenDatum(rekenAgendaPO.getRekenDatum());
        rekenagendaDTO.setBeslagDatum(rekenAgendaPO.getBeslagDatum());
        rekenagendaDTO.setBoekDatum(rekenAgendaPO.getBoekDatum());
        rekenagendaDTO.setRekengroep(convert(rekenAgendaPO.getRekenGroep()));
        rekenagendaDTO.setHoedanigheid(convert(rekenAgendaPO.getHoedanigheid()));
        rekenagendaDTO.setWerkgeverId(rekenAgendaPO.getWerkgever().getId());
        Integer werkgeverNr = werkgeverIdToWerkgeverNr.get(rekenAgendaPO.getWerkgever().getId());
        if (werkgeverNr != null) {
            rekenagendaDTO.setWerkgeverNr(werkgeverNr);
        }
        if (rekenAgendaPO.getPersoon() != null) {
            rekenagendaDTO.setPersoon(new PersoonDTO(rekenAgendaPO.getPersoon()));
            if (rekenAgendaPO.getPersoon().getOpdrachten() != null && Hibernate.isInitialized(rekenAgendaPO.getPersoon().getOpdrachten())) {
                for (Opdracht opdracht : rekenAgendaPO.getPersoon().getOpdrachten()) {
                    if (opdracht.getOpdrachtnr().compareTo(rekenAgendaPO.getOpdrachtNummer()) == 0) {
                        rekenagendaDTO.setHoedanigheid(new CodeEnumDTO(opdracht.getHoedanigheid()));
                    }
                }
            }
        }
        rekenagendaDTO.setOpdrachtNummer(rekenAgendaPO.getOpdrachtNummer());

        String label = getRekenAgendaLabel(rekenagendaDTO);
        rekenagendaDTO.setLabel(label);

        return rekenagendaDTO;
    }

    public List<ArtikelagendaDTO> convertArtikelagendas(List<ArtikelAgenda> artikelAgendas) {
        List<ArtikelagendaDTO> artikelagendaDTOs = new ArrayList<>();
        for (ArtikelAgenda artikelAgenda : artikelAgendas) {
            artikelagendaDTOs.add(convert(artikelAgenda));
        }
        return artikelagendaDTOs;
    }

    public ArtikelagendaDTO convert(ArtikelAgenda artikelAgendaPO) {
        ArtikelagendaDTO artikelagendaDTO = new ArtikelagendaDTO();
        setIdVersion(artikelagendaDTO, artikelAgendaPO);
        artikelagendaDTO.setBeginDatum(artikelAgendaPO.getBeginDatum());
        artikelagendaDTO.setEindDatum(artikelAgendaPO.getEindDatum());
        artikelagendaDTO.setStartBoekdatum(artikelAgendaPO.getStartBoekDatum());
        artikelagendaDTO.setStopBoekdatum(artikelAgendaPO.getStopBoekDatum());
        artikelagendaDTO.setStatus(new CodeEnumDTO(artikelAgendaPO.getStatus()));
        artikelagendaDTO.setWerkgeverId(artikelAgendaPO.getWerkgever().getId());
        artikelagendaDTO.setBron(new CodeEnumDTO(artikelAgendaPO.getBron()));
        artikelagendaDTO.setRnummer(artikelAgendaPO.getRnummer());
        Integer werkgeverNr = werkgeverIdToWerkgeverNr.get(artikelAgendaPO.getWerkgever().getId());
        if (werkgeverNr != null) {
            artikelagendaDTO.setWerkgeverNr(werkgeverNr);
        }

        artikelagendaDTO.setPersoon(new PersoonDTO(artikelAgendaPO.getPersoon()));
        if (artikelAgendaPO.getPersoon().getOpdrachten() != null && Hibernate
                .isInitialized(artikelAgendaPO.getPersoon().getOpdrachten())) {
            for (Opdracht opdracht : artikelAgendaPO.getPersoon().getOpdrachten()) {
                if (opdracht.getOpdrachtnr().compareTo(artikelAgendaPO.getOpdrachtNummer()) == 0) {
                    artikelagendaDTO.setHoedanigheid(new CodeEnumDTO(opdracht.getHoedanigheid()));
                }
            }
        }

        artikelagendaDTO.setOpdrachtNummer(artikelAgendaPO.getOpdrachtNummer());

        return artikelagendaDTO;
    }

    private String getRekenAgendaLabel(RekenagendaDTO rekenagendaDTO) {
        String label;
        CodeEnumDTO rekengroep = rekenagendaDTO.getRekengroep();
        CodeEnumDTO hoedanigheid = rekenagendaDTO.getHoedanigheid();
        PersoonDTO persoon = rekenagendaDTO.getPersoon();

        if (persoon != null && rekenagendaDTO.getOpdrachtNummer() != null) {
            label =
                    persoon.getPersoneelsNr() + "-" + rekenagendaDTO.getOpdrachtNummer() + " " + persoon.getFamilienaam() + " " + persoon.getVoornaam();

            if (hoedanigheid != null) {
                label += " " + hoedanigheid.getCode() + "-" + hoedanigheid.getLangeTekst();
            }
        } else if (rekengroep != null) {
            label = rekengroep.getCode() + "-" + rekengroep.getLangeTekst();
        } else if (hoedanigheid != null) {
            label = hoedanigheid.getCode() + "-" + hoedanigheid.getLangeTekst();
        } else {
            label = "Alles";
        }

        return label;
    }

    private String getVoorbereidingLabel(EvbDTO dto, Opdracht opdracht) {
        String label = "";
        CodeEnumDTO rekengroep = dto.getRekengroep();
        CodeEnumDTO hoedanigheid = dto.getHoedanigheid();

        if (opdracht != null && opdracht.getPersoon() != null) {
            Persoon persoon = opdracht.getPersoon();
            label = persoon.getPersoneelsNr() + "-" + opdracht.getOpdrachtnr() + " " + persoon.getFamilienaam() + " " + persoon.getVoornaam();
        } else if (rekengroep != null && Rekengroep.NULL.getCode() != rekengroep.getCode().intValue()) {
            label += rekengroep.getCode() + "-" + rekengroep.getLangeTekst() + " ";
        } else if (hoedanigheid != null) {
            label += hoedanigheid.getCode() + "-" + hoedanigheid.getLangeTekst() + " ";
        }

        return label;
    }

    public List<EvbDTO> convertVoorbereidingen(Collection<RekenVoorbereiding> voorbereidingen) {
        List<EvbDTO> evbDTOs = new ArrayList<>();
        for (RekenVoorbereiding voorbereiding : voorbereidingen) {
            evbDTOs.add(convert(voorbereiding));
        }
        return evbDTOs;
    }

    public Integer getWerkgeverId(RekenVoorbereiding voorbereiding) {
        Werkgever werkgever = werkgeverNrToWerkgever.get(voorbereiding.getElektronischeVoorbereiding().getWerkgeverNummer());
        if (werkgever == null) {
            return null;
        }
        return werkgever.getId();
    }

    public EvbDTO convert(RekenVoorbereiding rekenVoorbereiding) {
        ElektronischeVoorbereiding voorbereiding = rekenVoorbereiding.getElektronischeVoorbereiding();
        EvbDTO evbDTO = new EvbDTO();
        LocalDate beginDatum = new LocalDate(voorbereiding.getJaar(), voorbereiding.getMaand(), 1);
        evbDTO.setBeginDatum(beginDatum);
        evbDTO.setEindDatum(beginDatum.dayOfMonth().withMaximumValue());
        evbDTO.setRekenDatum(voorbereiding.getRekenDatum());
        evbDTO.setBeslagDatum(voorbereiding.getBeslagDatum());
        evbDTO.setBoekDatum(voorbereiding.getBoekDatum());
        evbDTO.setRekengroep(convert(voorbereiding.getRekengroep()));
        evbDTO.setHoedanigheid(convert(voorbereiding.getHoedanigheid()));
        evbDTO.setWerkgeverNr(voorbereiding.getWerkgeverNummer());
        Werkgever werkgever = werkgeverNrToWerkgever.get(voorbereiding.getWerkgeverNummer());
        if (werkgever != null) {
            evbDTO.setWerkgeverId(werkgever.getId());
        }

        evbDTO.setMetRegulagenda(voorbereiding.getMetRegulagenda());
        evbDTO.setIsKalenderOpdracht(rekenVoorbereiding.isKalenderOpdracht());
        Opdracht opdracht = rekenVoorbereiding.getOpdracht();
        evbDTO.setLabel(getVoorbereidingLabel(evbDTO, opdracht));

        evbDTO.setSoort(new CodeEnumDTO(voorbereiding.getSoort()));
        evbDTO.setVerwacht(voorbereiding.getMandatenVerwacht());
        evbDTO.setBetaaldatum(voorbereiding.getBetaaldatum());
        evbDTO.setBetalingPer(voorbereiding.getBetalingPer());
        evbDTO.setVoorbereidingId(voorbereiding.getVoorbereidingId());

        return evbDTO;
    }

    public void setIdVersion(IdentifiableVersionedDTO identifiableDTO, IdentifiableVersioned identifiable) {
        setId(identifiableDTO, identifiable);
        identifiableDTO.setVersion(identifiable.getVersion());
    }

    public void setId(IdentifiableDTO identifiableDTO, be.schaubroeck.util.persistence.Identifiable identifiable) {
        identifiableDTO.setId(identifiable.getId());
    }
}
